public enum AtheerError: Swift.Error, Equatable, Hashable, Foundation.LocalizedError {

    
    
    case ModelLoadFailed(message: String
    )
    case TokenizerLoadFailed(message: String
    )
    case GenerationFailed(message: String
    )
    case InvalidParameters(message: String
    )
    case NotInitialized
    case InvalidMode(String
    )

    

    

    
    public var errorDescription: String? {
        String(reflecting: self)
    }
    
}

#if compiler(>=6)
extension AtheerError: Sendable {}
#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeAtheerError: FfiConverterRustBuffer {
    typealias SwiftType = AtheerError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> AtheerError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .ModelLoadFailed(
            message: try FfiConverterString.read(from: &buf)
            )
        case 2: return .TokenizerLoadFailed(
            message: try FfiConverterString.read(from: &buf)
            )
        case 3: return .GenerationFailed(
            message: try FfiConverterString.read(from: &buf)
            )
        case 4: return .InvalidParameters(
            message: try FfiConverterString.read(from: &buf)
            )
        case 5: return .NotInitialized
        case 6: return .InvalidMode(
            try FfiConverterString.read(from: &buf)
            )

         default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: AtheerError, into buf: inout [UInt8]) {
        switch value {

        

        
        
        case let .ModelLoadFailed(message):
            writeInt(&buf, Int32(1))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .TokenizerLoadFailed(message):
            writeInt(&buf, Int32(2))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .GenerationFailed(message):
            writeInt(&buf, Int32(3))
            FfiConverterString.write(message, into: &buf)
            
        
        case let .InvalidParameters(message):
            writeInt(&buf, Int32(4))
            FfiConverterString.write(message, into: &buf)
            
        
        case .NotInitialized:
            writeInt(&buf, Int32(5))
        
        
        case let .InvalidMode(v1):
            writeInt(&buf, Int32(6))
            FfiConverterString.write(v1, into: &buf)
            
        }
    }
}


