    let scaffolding_contract_version = ffi_atheer_ffi_uniffi_contract_version()
    if bindings_contract_version != scaffolding_contract_version {
        return InitializationResult.contractVersionMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_crash_log_path() != 8200) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_generate_stream() != 24474) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_generate_sync() != 54248) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_initialize() != 44585) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_is_initialized() != 58606) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_load_draft() != 37769) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_poll_stream_token() != 5136) {
        return InitializationResult.apiChecksumMismatch
    }
    if (uniffi_atheer_ffi_checksum_method_atheerengine_set_mode() != 57912) {
        return InitializationResult.apiChecksumMismatch
    }
